#!/usr/bin/env bash
set -euo pipefail

# List Claude Code plugins discovered across every sub-repo listed in .meta.
#
# A sub-repo is a plugin when it has a top-level .claude-plugin/ directory:
#   marketplace.json  -> the repo ships its own marketplace; its plugins[]
#                        entries are the installable units
#   plugin.json only  -> plugin without a marketplace; installable via this
#                        meta-repo's synthesized 'meta-skills' marketplace
#                        (generated by install-plugins.sh)
#
# Usage:
#   ./plugins.sh list              # grouped by repo: name@marketplace — description
#
# Source of truth is .meta; sub-repos must already be cloned (make bootstrap).

repo_root="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"
meta_file="$repo_root/.meta"
cmd="${1:-list}"

if [[ ! -f "$meta_file" ]]; then
  echo "No .meta file at $meta_file (run from a meta-repo root)" >&2
  exit 1
fi

# Detect terminal width so descriptions stay on one line. COLUMNS is an explicit
# override; otherwise ask the controlling terminal directly (works even when our
# stdout is a pipe, e.g. under make or `| head`), then fall back to tput, then 80.
detect_cols() {
  local c
  if [[ "${COLUMNS:-}" =~ ^[0-9]+$ ]]; then echo "$COLUMNS"; return; fi
  c="$( { stty size </dev/tty | awk '{print $2}'; } 2>/dev/null || true )"
  [[ "$c" =~ ^[0-9]+$ && "$c" -gt 0 ]] && { echo "$c"; return; }
  c="$( (tput cols) 2>/dev/null || true )"
  [[ "$c" =~ ^[0-9]+$ && "$c" -gt 0 ]] && { echo "$c"; return; }
  echo 80
}
cols="$(detect_cols)"

projects=()
while IFS= read -r line; do
  [[ -n "$line" ]] && projects+=("$line")
done < <(node -e 'const p=JSON.parse(require("fs").readFileSync(process.argv[1],"utf8")).projects||{};for(const k of Object.keys(p))console.log(k)' "$meta_file")

# Truncate $1 to width $2, adding an ellipsis when cut.
truncate() {
  local t="$1" w="$2"
  (( w <= 1 )) && return
  if (( ${#t} > w )); then printf '%s…' "${t:0:w-1}"; else printf '%s' "$t"; fi
}

case "$cmd" in
  list)
    namecol=34
    plugin_count=0
    markets=""
    for proj in "${projects[@]}"; do
      proj_dir="$repo_root/$proj"
      [[ -d "$proj_dir" ]] || { echo "Warning: sub-repo not cloned, skipping: $proj (make update)" >&2; continue; }
      cp_dir="$proj_dir/.claude-plugin"
      rows=()   # id / description / source-note, \x1f-separated
      if [[ -f "$cp_dir/marketplace.json" ]]; then
        while IFS=$'\x1f' read -r mname pname stype sdetail desc; do
          [[ -n "$pname" ]] || continue
          case "$stype" in
            relative) note="source: follows the marketplace registration (origin by default; SOURCE=local uses the clone)" ;;
            github)   note="source: github $sdetail (pinned by its marketplace entry)" ;;
            *)        note="source: $stype $sdetail (pinned by its marketplace entry)" ;;
          esac
          rows+=("$pname@$mname"$'\x1f'"$desc"$'\x1f'"$note")
          case " $markets " in *" $mname "*) ;; *) markets="$markets $mname" ;; esac
        done < <(node -e '
          const m=JSON.parse(require("fs").readFileSync(process.argv[1],"utf8"));
          for(const p of m.plugins||[]){
            let st="relative", sd="";
            if(p.source&&typeof p.source==="object"){st=p.source.source||"?";sd=p.source.repo||p.source.url||""}
            console.log([m.name,p.name,st,sd,(p.description||"").replace(/[\t\u001f]/g," ")].join("\u001f"))
          }' "$cp_dir/marketplace.json")
      elif [[ -f "$cp_dir/plugin.json" ]]; then
        IFS=$'\x1f' read -r pname desc < <(node -e '
          const m=JSON.parse(require("fs").readFileSync(process.argv[1],"utf8"));
          console.log([m.name||"",(m.description||"").replace(/[\t\u001f]/g," ")].join("\u001f"))' "$cp_dir/plugin.json")
        [[ -n "$pname" ]] || pname="$proj"
        rows+=("$pname@meta-skills"$'\x1f'"$desc"$'\x1f'"source: synthesized 'meta-skills' marketplace (origin by default; SOURCE=local uses the clone)")
        case " $markets " in *" meta-skills "*) ;; *) markets="$markets meta-skills" ;; esac
      else
        continue
      fi
      printf '\n\033[1m%s\033[0m\n' "$proj"
      for row in "${rows[@]}"; do
        IFS=$'\x1f' read -r id desc note <<< "$row"
        plugin_count=$((plugin_count + 1))
        local_field=$(( ${#id} > namecol ? ${#id} : namecol ))
        printf '  \033[36m%s\033[0m%*s ' "$id" $(( local_field - ${#id} )) ''
        remain=$(( cols - 2 - local_field - 1 ))
        if [[ -n "$desc" && $remain -gt 1 ]]; then truncate "$desc" "$remain"; fi
        printf '\n'
        printf '    \033[2m%s\033[0m\n' "$note"
      done
    done
    if [[ "$plugin_count" -eq 0 ]]; then
      echo "No Claude Code plugins found across sub-repos (looked for .claude-plugin/)." >&2
      exit 1
    fi
    market_count=$(echo "$markets" | wc -w | tr -d ' ')
    printf '\n%d plugin(s) across %d marketplace(s) — install with '\''make install-plugins'\''\n' "$plugin_count" "$market_count"
    ;;
  *)
    echo "Unknown command: $cmd (use 'list')" >&2
    exit 1
    ;;
esac
